import React from 'react';

export const BannerIlustracion = () => {
  return (
    <svg
      viewBox="0 0 420 280"
      xmlns="http://www.w3.org/2000/svg"
      style={{ width: '100%', maxWidth: '420px', height: 'auto' }}
    >
      {/* ── MONITOR ── */}
      <rect x="90" y="30" width="240" height="155" rx="10" fill="#0f1c2e" stroke="#1e3a5f" strokeWidth="3"/>
      {/* pantalla */}
      <rect x="100" y="40" width="220" height="135" rx="6" fill="#0d2137"/>
      {/* brillo pantalla */}
      <rect x="100" y="40" width="220" height="30" rx="6" fill="#112840" opacity="0.5"/>

      {/* contenido en pantalla — tienda */}
      <rect x="110" y="52" width="80" height="6" rx="3" fill="#00c6ff" opacity="0.8"/>
      <rect x="110" y="64" width="130" height="4" rx="2" fill="#1e4060" />
      <rect x="110" y="73" width="100" height="4" rx="2" fill="#1e4060" />

      {/* tarjetas de producto en pantalla */}
      <rect x="110" y="85" width="58" height="72" rx="5" fill="#112840" stroke="#1e3a5f" strokeWidth="1"/>
      <rect x="114" y="89" width="50" height="38" rx="3" fill="#0a1929"/>
      <rect x="118" y="97" width="42" height="5" rx="2" fill="#00c6ff" opacity="0.4"/>
      <rect x="118" y="106" width="30" height="4" rx="2" fill="#1e4060"/>
      <rect x="114" y="132" width="30" height="5" rx="2" fill="#00c6ff" opacity="0.7"/>
      <rect x="114" y="141" width="20" height="4" rx="2" fill="#1e3a5f"/>

      <rect x="176" y="85" width="58" height="72" rx="5" fill="#112840" stroke="#1e3a5f" strokeWidth="1"/>
      <rect x="180" y="89" width="50" height="38" rx="3" fill="#0a1929"/>
      <rect x="184" y="97" width="42" height="5" rx="2" fill="#00c6ff" opacity="0.4"/>
      <rect x="184" y="106" width="30" height="4" rx="2" fill="#1e4060"/>
      <rect x="180" y="132" width="30" height="5" rx="2" fill="#00c6ff" opacity="0.7"/>
      <rect x="180" y="141" width="20" height="4" rx="2" fill="#1e3a5f"/>

      <rect x="242" y="85" width="58" height="72" rx="5" fill="#112840" stroke="#1e3a5f" strokeWidth="1"/>
      <rect x="246" y="89" width="50" height="38" rx="3" fill="#0a1929"/>
      <rect x="250" y="97" width="42" height="5" rx="2" fill="#00c6ff" opacity="0.4"/>
      <rect x="250" y="106" width="30" height="4" rx="2" fill="#1e4060"/>
      <rect x="246" y="132" width="30" height="5" rx="2" fill="#00c6ff" opacity="0.7"/>
